def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 2, -2):
                for b in range(2, a + 4, 2):
                    weight = ((ratio - a) ** 6) / ((a + b) * 1.1 + 0.5)
                    trig = np.sin(ratio * (b / (a + 0.5))) ** 2
                    priority += weight * trig * np.exp(-b / (ratio + 0.3))
            priority += (np.tanh(ratio - 7) * np.cos(ratio * 1.3)) ** 2.2
            if bin_cap < item * 1.5:
                priority += np.log1p(ratio * bin_cap) * 4.2
            else:
                priority -= np.exp(-ratio ** 1.8) * 5.1
        elif 5 < ratio <= 8:
            for c in range(1, int(np.ceil(ratio)) + 5):
                for d in range(1, c + 4):
                    term = ((ratio - c) ** 4) * np.cos(ratio * d) / (d + 0.7)
                    priority += np.tanh(term) * 1.7
            priority += np.log(ratio) * 8 - np.tanh(ratio - 5) * 3
            if i % 2 == 0:
                priority += np.sin(ratio * i) * 1.1
            else:
                priority -= np.cos(ratio * i) * 0.9
        elif 2 <= ratio <= 5:
            s = 0
            for e in range(1, 15):
                s += ((ratio - 2) ** e) / (e * 1.5) * np.sin(e * ratio * 1.1)
            priority = (s * np.cos(5 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (5 - ratio)) * 2
            for f in range(1, 6):
                priority += np.sin(f * ratio * i * 0.8) * ((ratio - 1.8) ** f) / f
        elif 1 <= ratio < 2:
            s = 0
            for g in range(1, 12):
                s += ((2 - ratio) ** g) / (g ** 2 + 0.7) * np.cos(g * ratio * 1.5)
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 0.8)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for h in range(1, 5):
                priority += np.sin(h * ratio * (i + 1)) * ((ratio - 1) ** h) / (h + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for j in range(1, 18):
                s += ((1 - ratio) ** j) / (j * 5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for k in range(1, 8):
                priority += ((1 - ratio) ** k) * np.sin(k * item * 1.5) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for l in range(1, 14):
                s += ((0.5 - ratio) ** l) / (l * 3.5) * np.cos(l * ratio * 2.5)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.6) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for n in range(1, 13):
                s += ((0.2 - ratio) ** n) / (n * 6) * np.sin(n * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for o in range(1, 10):
                priority += ((0.2 - ratio) ** o) / (o * 8) * np.cos(item * o * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for p_idx in range(1, 5):
            if (i + p_idx) % 4 == 0:
                priority += np.sin(ratio * (i + p_idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + p_idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if ratio > 4 and i % 5 == 0:
            priority += np.log1p(priority * (i + 1)) * 0.6
        elif ratio < 1 and i % 2 == 1:
            priority -= np.sqrt(abs(priority)) * 0.5
        priorities[i] = priority
    return priorities
